const body = $input.first().json.body ?? $input.first().json;
const esc = (value) => String(value).replace(/'/g, "''");
const sqlText = (value) => value == null || value === '' ? 'NULL' : `'${esc(value)}'`;
const sqlTimestamp = (value, field) => {
  if (!value) {
    if (field === 'end_datetime') return 'NULL';
    throw new Error(`${field} is required`);
  }
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) throw new Error(`Invalid ${field}: ${value}`);
  return `'${esc(String(value).replace(/Z$/, ''))}'`;
};
const assertUuid = (value, field) => {
  const text = String(value ?? '').trim();
  if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(text)) {
    throw new Error(`Invalid ${field}: ${value}`);
  }
  return text;
};
const sqlUuid = (value, field) => {
  if (!value) return 'NULL';
  return `'${esc(assertUuid(value, field))}'`;
};
const makeUuid = () => {
  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') return crypto.randomUUID();
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (char) => {
    const rand = Math.random() * 16 | 0;
    const value = char === 'x' ? rand : (rand & 0x3 | 0x8);
    return value.toString(16);
  });
};

const title = String(body.title ?? '').trim();
if (!title) throw new Error('title is required');

const priority = String(body.priority ?? 'MEDIUM').toUpperCase().trim();
const status = String(body.status ?? 'pending').toLowerCase().trim();
const visibility = String(body.visibility ?? 'clinic').toLowerCase().trim();

const VALID_PRIORITY = ['LOW', 'MEDIUM', 'HIGH'];
const VALID_STATUS = ['pending', 'done', 'dismissed', 'cancelled'];
if (!VALID_PRIORITY.includes(priority)) throw new Error(`Invalid priority: ${body.priority}`);
if (!VALID_STATUS.includes(status)) throw new Error(`Invalid status: ${body.status}`);
if (visibility !== 'clinic') throw new Error(`Invalid visibility: ${body.visibility}`);

const id = body.id ? assertUuid(body.id, 'id') : makeUuid();
const startSql = sqlTimestamp(body.start_datetime, 'start_datetime');
const endSql = sqlTimestamp(body.end_datetime, 'end_datetime');
const createdBySql = sqlUuid(body.created_by, 'created_by');
const completedBySql = sqlUuid(body.completed_by ?? body.changed_by, 'completed_by');

return [{ json: {
  id,
  id_sql: `'${esc(id)}'::uuid`,
  title_sql: sqlText(title),
  description_sql: sqlText(body.description),
  start_datetime_sql: startSql,
  end_datetime_sql: endSql,
  color_sql: sqlText(body.color || '#8b5cf6'),
  priority_sql: `'${priority}'`,
  status_sql: `'${status}'`,
  visibility_sql: `'${visibility}'`,
  raise_alert_sql: body.raise_alert === true ? 'TRUE' : 'FALSE',
  created_by_sql: createdBySql,
  completed_by_sql: completedBySql,
} }];

const rows = $input.all().map(item => item.json).filter(row => row.id);
if (rows.length === 0) throw new Error('Reminder upsert failed — no reminder row found after save');
return [{ json: { success: true, code: 200, reminder: rows[0] } }];
